args.sparql:
SELECT ?cityLabel WHERE {
  { ?event wdt:P31 wd:Q23222; wdt:P585 ?eventDate; wdt:P118 ?city. }
  UNION
  { ?event wdt:P31 wd:Q23224; wdt:P585 ?eventDate; wdt:P118 ?city. }
  ?city rdfs:label ?cityLabel.
  FILTER(lang(?cityLabel) = 'en').
  FILTER(?eventDate > "2023-12-31"^^xsd:date)
} ORDER BY ?eventDate LIMIT 2

SELECT ?cityLabel WHERE {
  ?event wdt:P31 wd:Q23222;
         wdt:P585 ?eventDate;
         wdt:P118 ?city.
  ?city rdfs:label ?cityLabel.
  FILTER(lang(?cityLabel) = 'en').
  FILTER(?eventDate > "2024-01-01"^^xsd:date)
} ORDER BY ?eventDate LIMIT 2
